#include <stdio.h>

#define N 32

static float A[N][N];
static float B[N][N];
static float C[N][N];

static void init(void) {
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            A[i][j] = (float)(i + j);
            B[i][j] = (float)(i - j);
            C[i][j] = 0.0f;
        }
    }
}

static void gemm(void) {
    for (int i = 0; i < N; i++) {
        for (int k = 0; k < N; k++) {
            float a = A[i][k];
            for (int j = 0; j < N; j++) {
                C[i][j] += a * B[k][j];
            }
        }
    }
}

int main(void) {
    init();
    gemm();
    printf("C[0][0]=%f C[N-1][N-1]=%f\n", C[0][0], C[N-1][N-1]);
    return 0;
}

